!function ($) {
    function hideContextMenus() {
        $("[data-site-cm-root='1']").remove();
    }

    $.fn.contextMenu = function (menuData, opts) {
        var settings = $.extend({ name: "", offsetX: 15, offsetY: 5, beforeShow: $.noop, afterShow: $.noop }, opts || {});
        var $body = $("body");

        return this.each(function () {
            $(this).on("contextmenu", function (e) {
                e.preventDefault();
                e.stopPropagation();
                if ($.isFunction(settings.beforeShow) && settings.beforeShow.call(this, e) === false) {
                    hideContextMenus();
                    return;
                }
                hideContextMenus();

                var actions = {};
                var keyIx = 0;
                var instancePrefix = "cm_" + Date.now() + "_" + Math.floor(Math.random() * 1e6);

                function buildGroups(groups) {
                    var $box = $('<div class="site-cm-box" style="position:absolute;display:none;"/>');
                    $.each(groups, function (gi, group) {
                        if (!$.isArray(group)) {
                            throw new TypeError("contextMenu: each menu group must be an array");
                        }
                        if (gi > 0) {
                            $box.append('<div class="site-cm-separ"/>');
                        }
                        if (!group.length) {
                            return;
                        }
                        var $ul = $('<ul class="site-cm-group"/>');
                        $.each(group, function (ii, item) {
                            var label = item && item.text != null ? String(item.text) : "";
                            var $li = $("<li/>").text(label);
                            if (item && $.isArray(item.items) && item.items.length) {
                                $li.addClass("site-cm-has-submenu");
                                $li.append(buildGroups(item.items));
                            }
                            if (item && $.isFunction(item.action)) {
                                var k = instancePrefix + "_" + (keyIx++);
                                actions[k] = item.action;
                                $li.attr("data-key", k);
                            }
                            $ul.append($li);
                        });
                        $box.append($ul);
                    });
                    return $box;
                }

                var resolvedData = $.isFunction(menuData) ? menuData.call(this, e) : menuData;
                var $menu = buildGroups(resolvedData);
                $menu.attr("data-site-cm-root", "1").appendTo($body);

                $menu
                    .on("mouseenter", "li", function () {
                        var $li = $(this);
                        $li.parent("ul.site-cm-group").children("li").not($li)
                            .removeClass("hover")
                            .children(".site-cm-box")
                            .hide();
                        $li.addClass("hover").children(".site-cm-box").show();
                    })
                    .on("mouseleave", "li", function (e) {
                        var rt = e.relatedTarget;
                        if (rt && (this === rt || $.contains(this, rt))) {
                            return;
                        }
                        $(this).removeClass("hover").children(".site-cm-box").hide();
                    })
                    .on("click", "li", function () {
                        var k = $(this).attr("data-key");
                        if (k && actions[k] && actions[k].call(this) !== false) {
                            hideContextMenus();
                        }
                    })
                    .on("contextmenu", function () {
                        return false;
                    });

                $menu.show().css({
                    position: "absolute",
                    left: e.clientX + settings.offsetX,
                    top: e.clientY + settings.offsetY,
                    zIndex: 10000,
                });

                if ($.isFunction(settings.afterShow)) {
                    settings.afterShow.call(this, e);
                }
            });
        });
    };

    $(function () {
        $(document).on("mousedown", function (ev) {
            if (!$(ev.target).closest(".site-cm-box").length) {
                hideContextMenus();
            }
        });
    });
}(jQuery);
